const std = @import("std");

pub fn main() !void {
    // Get the default PRNG seeded with entropy from the OS.
    var prng = std.crypto.random.prng();
    const random = prng.random();

    const min: i32 = 1;
    const max: i32 = 100;

    // Generate random integer in range [min, max] (inclusive)
    // intRange requires T: comptime_int
    const random_int = random.intRange(i32, min, max);
    std.debug.print("Random integer ({d}-{d}): {d}\n", .{ min, max, random_int });

    // Generate random float (f32 or f64) between 0.0 and 1.0
    const random_f32 = random.float(f32);
    std.debug.print("Random f32 [0.0, 1.0): {}\n", .{random_f32});

    const random_f64 = random.float(f64);
    std.debug.print("Random f64 [0.0, 1.0): {}\n", .{random_f64});

    // Generate random boolean
    const random_bool = random.boolean();
    std.debug.print("Random boolean: {}\n", .{random_bool});
}

