const std = @import("std");

// Reverses a slice of bytes (u8) in place.
// WARNING: This reverses BYTES, not UTF-8 grapheme clusters.
// Reversing "你好" (bytes: e4 bd a0 e5 a5 bd) results in "½¥ å¤" (bytes: bd a5 e5 a0 bd e4)
fn reverseBytesInPlace(input_slice: []u8) void {
    if (input_slice.len <= 1) return;

    var i: usize = 0;
    var j: usize = input_slice.len - 1;
    while (i < j) {
        const temp = input_slice[i];
        input_slice[i] = input_slice[j];
        input_slice[j] = temp;
        i += 1;
        j -= 1;
    }
}

// Reverses a string by creating a new allocated string (allocator needed).
// Also reverses bytes, same UTF-8 caveat applies.
fn reverseBytesAlloc(allocator: std.mem.Allocator, input: []const u8) ![]u8 {
    const len = input.len;
    const reversed_slice = try allocator.alloc(u8, len);
    errdefer allocator.free(reversed_slice);

    for (input, 0..) |byte, i| {
        reversed_slice[len - 1 - i] = byte;
    }
    return reversed_slice;
}


pub fn main() !void {
    // --- In-place reversal ---
    // Note: String literals are const, so we need a mutable buffer.
    var buffer: [11]u8 = undefined; // Buffer large enough for "Hello World"
    @memcpy(&buffer, "Hello World");
    var mutable_slice: []u8 = &buffer;

    std.debug.print("Original (in-place): {s}\n", .{mutable_slice});
    reverseBytesInPlace(mutable_slice);
    std.debug.print("Reversed (in-place): {s}\n", .{mutable_slice});

    // --- Allocation reversal ---
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const original_alloc = "Zig Language";
    std.debug.print("Original (alloc): {s}\n", .{original_alloc});

    const reversed_alloc = try reverseBytesAlloc(allocator, original_alloc);
    defer allocator.free(reversed_alloc); // Free the allocated memory
    std.debug.print("Reversed (alloc): {s}\n", .{reversed_alloc});

    // UTF-8 Example Warning
    var utf8_buffer: [6]u8 = undefined;
    @memcpy(&utf8_buffer, "你好");
    var utf8_slice : []u8 = &utf8_buffer;
     std.debug.print("Original UTF-8: {s}\n", .{utf8_slice});
     reverseBytesInPlace(utf8_slice);
     std.debug.print("Reversed Bytes UTF-8 (likely broken): {s}\n", .{utf8_slice});

}

