const std = @import("std");

// Generates the first n Fibonacci numbers iteratively into an ArrayList.
// Uses u64, will panic on overflow in safe build modes.
fn generateFibonacci(allocator: std.mem.Allocator, n: usize) !std.ArrayList(u64) {
    var sequence = std.ArrayList(u64).init(allocator);
    errdefer sequence.deinit(); // Ensure deallocation on error

    if (n == 0) return sequence;

    var a: u64 = 0;
    var b: u64 = 1;

    try sequence.append(a);
    if (n == 1) return sequence;

    try sequence.append(b);
    if (n == 2) return sequence;

    var i: usize = 2;
    while (i < n) : (i += 1) {
        // In Debug/ReleaseSafe, this panics on overflow. ReleaseFast wraps.
        const next = a +% b; // Use +% for wrapping addition if needed in ReleaseFast
        try sequence.append(next);
        a = b;
        b = next;
    }

    return sequence;
}

pub fn main() !void {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const num_terms = 10;
    const fib_sequence = try generateFibonacci(allocator, num_terms);
    defer fib_sequence.deinit(); // Free the ArrayList memory

    std.debug.print("Fibonacci Sequence (first {d} terms):\n", .{num_terms});
    // Print the slice détenu par l'ArrayList
    std.debug.print("{any}\n", .{fib_sequence.items});

