factorial:
const std = @import("std");

// Calculates factorial iteratively.
// Uses u64. Panics on overflow in safe build modes (n > 20).
fn factorial(n: u32) u64 {
    if (n == 0) {
        return 1;
    }
    // Factorial grows very fast, u64 overflows after n=20
    if (n > 20) {
        std.debug.print("Warning: Factorial input {d} > 20 likely overflows u64!\n", .{n});
    }

    var result: u64 = 1;
    var i: u32 = 1;
    while (i <= n) : (i += 1) {
        // In Debug/ReleaseSafe, this panics on overflow. ReleaseFast wraps.
        result *%= i; // Use *%= for wrapping multiplication if needed in ReleaseFast
    }
    return result;
}

// Using comptime evaluation for compile-time calculation
comptime {
    const fact5 = factorial(5);
    std.debug.assert(fact5 == 120); // Verify at compile time
}

pub fn main() !void {
    const num5 = 5;
    std.debug.print("Factorial of {d} = {d}\n", .{ num5, factorial(num5) });

    const num0 = 0;
    std.debug.print("Factorial of {d} = {d}\n", .{ num0, factorial(num0) });

    const num20 = 20; // Max for u64
    std.debug.print("Factorial of {d} = {d}\n", .{ num20, factorial(num20) });

    const num21 = 21; // Will overflow u64 and panic in safe modes
    std.debug.print("Attempting Factorial of {d}...\n", .{num21});
    // const result21 = factorial(num21); // Uncommenting this will likely cause panic
    // std.debug.print("Factorial of {d} = {d}\n", .{ num21, result21 });
}

