const std = @import("std");

// Checks if a number is prime.
// Input type u64, adjust if needed.
fn isPrime(n: u64) bool {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 == 0 or n % 3 == 0) return false;

    // Use integer square root for the limit
    const limit = std.math.intSqrt(n);

    var i: u64 = 5;
    // Check i and i+2 based on 6k +/- 1 optimization
    while (i <= limit) : (i += 6) {
        if (n % i == 0 or n % (i + 2) == 0) {
            return false;
        }
    }

    return true;
}

pub fn main() !void {
    const nums_to_check = [_]u64{ 0, 1, 2, 3, 4, 17, 25, 29, 97, 100, 104729 };

    for (nums_to_check) |num| {
        if (isPrime(num)) {
            std.debug.print("{d} is a prime number.\n", .{num});
        } else {
            std.debug.print("{d} is not a prime number.\n", .{num});
        }
    }
}

