writeFile:
const std = @import("std");

pub fn main() !void {
    const filename = "output_zig.txt";
    const content_to_write = "Hello from Zig!\nWriting to a file using std.fs.\nLine 3 with UTF-8: 你好\n";

    std.debug.print("--- Writing to file (overwrite): {s} ---\n", .{filename});

    // Create or truncate the file and open for writing
    // The .{ .truncate = true } option is implicit with createFile
    const file_write = try std.fs.cwd().createFile(filename, .{});
    defer file_write.close();

    // Get a writer interface
    const writer = file_write.writer();

    // Write the entire string content
    try writer.writeAll(content_to_write);

    std.debug.print("Successfully wrote initial content.\n", .{});

    // --- Appending to the file ---
    std.debug.print("\n--- Appending to file: {s} ---\n", .{filename});
    const content_to_append = "Appending this line.\nAnd another line.\n";

    // Open the file with append and create-if-not-exists flags
    const file_append = try std.fs.cwd().openFile(filename, .{
        .mode = .write_only,
        .append = true,
        .create = true, // Create if it doesn't exist (though it should now)
    });
    defer file_append.close();

    try file_append.writer().writeAll(content_to_append);

    std.debug.print("Successfully appended content.\n", .{});
    std.debug.print("Check content of {s}.\n", .{filename});
}

