const std = @import("std");

// Checks using std.fs.access (preferred for simple existence check)
fn checkExistsAccess(path: []const u8) void {
    // std.fs.access checks if path exists and has specified permissions (mode=0 checks existence)
    const result = std.fs.cwd().access(path, 0);

    std.debug.print("'{s}' -> access(): ", .{path});
    if (result == .ok) {
        std.debug.print("OK (Exists)\n", .{});
    } else |err| {
        if (err == error.FileNotFound) {
             std.debug.print("ERROR: File Not Found\n", .{});
        } else {
             std.debug.print("ERROR: {s}\n", .{@errorName(err)});
        }
    }
}

// Checks using std.fs.statFile (gives more info, errors if not found)
fn checkExistsStat(path: []const u8) void {
     std.debug.print("'{s}' -> statFile(): ", .{path});
     const stat = std.fs.cwd().statFile(path); // Returns error union

     if (stat) |file_stat| {
         const file_type = file_stat.kind;
         std.debug.print("OK (Type: {s})\n", .{@tagName(file_type)});
     } else |err| {
          if (err == error.FileNotFound) {
             std.debug.print("ERROR: File Not Found\n", .{});
         } else {
             std.debug.print("ERROR: {s}\n", .{@errorName(err)});
         }
     }
}


pub fn main() !void {
    // Assuming 'code-snippets.php' exists, 'snippets' is a dir,
    // 'output_zig.txt' was created, and 'nonexistent...' does not exist.

    const paths_to_check = [_][]const u8{
        "code-snippets.php",
        "output_zig.txt",
        "nonexistent_xyz123.zig",
        "snippets", // Directory
    };

    std.debug.print("--- Checking using std.fs.access (Existence) ---\n", .{});
    for (paths_to_check) |p| {
        checkExistsAccess(p);
    }

    std.debug.print("\n--- Checking using std.fs.statFile (Type) ---\n", .{});
    for (paths_to_check) |p| {
        checkExistsStat(p);
    }
}

