const std = @import("std");

// Finds the maximum value in a slice of integers.
// Returns null if the slice is empty.
// Works for any integer type T.
fn maxInSlice(comptime T: type, slice: []const T) ?T {
    if (slice.len == 0) {
        return null;
    }

    var max_val = slice[0]; // Assume first element is max
    for (slice[1..]) |value| {
        if (value > max_val) {
            max_val = value;
        }
    }
    return max_val;
}

pub fn main() !void {
    const numbers = [_]i32{ 10, 5, 42, 17, 8, 99, 32, -5, 0 };
    const empty_slice: []const i32 = &.{};
    const single_element = [_]i32{50};

    std.debug.print("Slice: {any}\n", .{numbers});

    // Find max in 'numbers' slice
    if (maxInSlice(i32, &numbers)) |max_num| {
        std.debug.print("Maximum value: {d}\n", .{max_num});
    } else {
        std.debug.print("Slice was empty, no maximum.\n", .{});
    }

    // Find max in 'empty_slice'
    std.debug.print("\nSlice: {any}\n", .{empty_slice});
     if (maxInSlice(i32, empty_slice)) |max_num| {
        std.debug.print("Maximum value: {d} (Should not happen)\n", .{max_num});
    } else {
        std.debug.print("Slice was empty, no maximum.\n", .{});
    }

     // Find max in 'single_element' slice
    std.debug.print("\nSlice: {any}\n", .{single_element});
     if (maxInSlice(i32, &single_element)) |max_num| {
        std.debug.print("Maximum value: {d}\n", .{max_num});
    } else {
        std.debug.print("Slice was empty, no maximum.\n", .{});
    }
}
